    statement_no character varying(64) NOT NULL,
    carrier_name character varying(128) NOT NULL,
    start_date timestamp without time zone NOT NULL,
    end_date timestamp without time zone NOT NULL,
    total_weight numeric(18,8) NOT NULL,
    total_freight numeric(14,2) NOT NULL,
    paid_amount numeric(14,2) NOT NULL,
    unpaid_amount numeric(14,2) NOT NULL,
    status character varying(16) NOT NULL,
    sign_status character varying(16) NOT NULL,
    attachment character varying(500),
    remark character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    version bigint,
    carrier_code character varying(64),
    settlement_company_id bigint,
    settlement_company_name character varying(128)
)
WITH (fillfactor='70');


