--
-- Name: md_carrier; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.md_carrier (
    id bigint NOT NULL,
    carrier_code character varying(64) NOT NULL,
    carrier_name character varying(128) NOT NULL,
    contact_name character varying(32),
    contact_phone character varying(20),
    vehicle_type character varying(64),
    price_mode character varying(32),
    status character varying(16) NOT NULL,
    remark character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    vehicle_plates text,
    default_settlement_company_id bigint,
    default_settlement_company_name character varying(128),
    CONSTRAINT chk_carrier_status CHECK (((status)::text = ANY ((ARRAY['正常'::character varying, '禁用'::character varying])::text[])))
);


--
-- Name: COLUMN md_carrier.vehicle_plates; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.md_carrier.vehicle_plates IS 'JSON array of {plate, contact} for multi-vehicle carriers';


--
-- Name: md_customer; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.md_customer (
    id bigint NOT NULL,
