    customer_name character varying(128) NOT NULL,
    contact_name character varying(32),
    contact_phone character varying(20),
    city character varying(64),
    settlement_mode character varying(32),
    status character varying(16) NOT NULL,
    remark character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    project_name character varying(200) NOT NULL,
    project_name_abbr character varying(64),
    project_address character varying(255),
    default_settlement_company_id bigint,
    default_settlement_company_name character varying(128),
    CONSTRAINT chk_customer_status CHECK (((status)::text = ANY ((ARRAY['正常'::character varying, '禁用'::character varying])::text[])))
);


--
-- Name: md_material; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.md_material (
    id bigint NOT NULL,
    material_code character varying(64) NOT NULL,
    brand character varying(64) NOT NULL,
    material character varying(16) NOT NULL,
    category character varying(16) NOT NULL,
    spec character varying(64) NOT NULL,
    length character varying(32),
    unit character varying(8) NOT NULL,
    piece_weight_ton numeric(18,8) NOT NULL,
    pieces_per_bundle integer NOT NULL,
    unit_price numeric(12,2) NOT NULL,
    remark character varying(255),
    created_by bigint DEFAULT 0 NOT NULL,
    created_name character varying(64) DEFAULT 'system'::character varying NOT NULL,
    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_by bigint,
    updated_name character varying(64),
    updated_at timestamp without time zone,
    deleted_flag boolean DEFAULT false NOT NULL,
    quantity_unit character varying(8) DEFAULT '件'::character varying NOT NULL,
    batch_no_enabled boolean DEFAULT false NOT NULL,
    length_sort numeric GENERATED ALWAYS AS ((NULLIF(regexp_replace((COALESCE(length, '0'::character varying))::text, '[^0-9.]'::text, ''::text, 'g'::text), ''::text))::numeric) STORED,
